INSERT INTO public.photos VALUES (21460, 'Huelga General 1911', 'Imagen posiblemente capturada en el Arrabal y centrada en el estrat├®gico cruce entre la calle de Jes├║s y su continuidad hacia la derecha por el camino del Vado, y el camino que desde la carretera de Madrid a Francia (al fondo) conduc├¡a al puente del Pilar o de Hierro, durante la Huelga General del verano de 1911 cuando guardiaciviles a pie y a caballo, guardias del cuerpo de seguridad y tropas de caballer├¡a de los regimientos de los Castillejos y Lanceros patrullaban las calles y zonas de acceso a la ciudad, adem├ís de ejercer vigilancia en las principales f├íbricas y talleres.', 1911, 1911, 1911, 'Anos 10', 'EL RABAL', 41.65772500, -0.86948500, '0101000020E6100000179AEB34D2D2EBBF7C61325530D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52185910678.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52185910678.webp', 'https://www.flickr.com/photos/zaragozaantigua/52185910678/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21647, 'Calle de la Estaci├│n 1925', 'Imagen capturada en el gran patio de la casa del industrial Sancerni en la calle de la Estaci├│n n┬║ 3-5 durante una verbena particular celebrada con motivo de las fiestas del barrio de Jes├║s organizadas a mediados del mes de junio. Posan en ella algunas muchachas de las familias de bien que participaron engalanadas con los muy tradicionales y espa├▒oles mantones de Manila: Mar├¡a Luisa y Alicia Sancerni, Maurita Sandoval, Conchita y Teresa Lanuza, Teresita Villegas, Mar├¡a y Emilia Aguelo, Conchita Villena, Elvira y Pilar del R├¡o, Mar├¡a Redondo, la se├▒ora de Ca├▒averal, Aurora y Pilar Guti├®rrez, Emilia y Pilar Echegoyen, y Mar├¡a Redondo. Alguna ni├▒a se ha colado en el posado, y son las ├║nicas que miran al objetivo. Julio Sancerni habilit├│ en la calle de la Estaci├│n una importante fundici├│n de hierro, bronce y cobre de la que salieron hasta campanas de iglesia, y unos talleres de fabricaci├│n de calderer├¡a, cocinas econ├│micas, m├íquinas agr├¡colas, construcciones y telas met├ílicas.', 1925, 1925, 1925, 'Anos 20', 'EL RABAL', 41.65878900, -0.87151400, '0101000020E61000005532005471E3EBBF76FBAC3253D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51344611414.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51344611414.webp', 'https://www.flickr.com/photos/zaragozaantigua/51344611414/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21845, 'Plaza de Jes├║s 1934', 'Imagen de la plaza de Jes├║s capturada con su nuevo aspecto tras la reciente reforma y adoquinado de la calle de Jes├║s, que contin├║a por la derecha hasta el cruce con la avenida del Puente del Pilar, tras el que contin├║a como camino del Vado. Hacia la izquierda de la plaza, fuera de plano, inicio de la calle de Valima├▒a, que luego contin├║a como camino hom├│nimo. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'EL RABAL', 41.65817400, -0.87068600, '0101000020E6100000C7B8E2E2A8DCEBBFEC89AE0B3FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35654391044.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35654391044.webp', 'https://www.flickr.com/photos/zaragozaantigua/35654391044/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22157, 'Franciscanos 1955', 'Procesi├│n de San Antonio de Padua, con alumnos del colegio de San Francisco de As├¡s (convento ubicado, desde 1940 en el camino del Vado n┬║ 9, con residencia, colegio e iglesia), por el barrio de Jes├║s. La imagen se ha obtenido, en un natural posado, en la plaza de Jes├║s. Al fondo, a la derecha, la calle de Funes, con una peque├▒a vista lateral del cuartel de la Guardia Civil de la calle de Jes├║s. Fuente: www.ofmval.org/', 1955, 1955, 1955, 'Anos 50', 'EL RABAL', 41.65812400, -0.87097700, '0101000020E6100000A12E52280BDFEBBF3A5B40683DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30370689333.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30370689333.webp', 'https://www.flickr.com/photos/zaragozaantigua/30370689333/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22399, 'Calle Estaci├│n c.1966', 'Vista de la calle de la Estaci├│n, con la plaza de Jes├║s al fondo. Fuente: www.facebook.com/photo.php?fbid=10204966991847910&set...', 1966, 1966, 1966, 'Anos 60', 'EL RABAL', 41.65859600, -0.87148200, '0101000020E61000007DAF21382EE3EBBF62A3ACDF4CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23239319049.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23239319049.webp', 'https://www.flickr.com/photos/zaragozaantigua/23239319049/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22447, 'C.┬║ del Vado 1966', 'Imagen a├®rea durante la construcci├│n del nuevo enlace para derivar las comunicaciones ferroviarias entre Zaragoza y Huesca desde el empalme de Miraflores. Hasta ese momento, la conexi├│n se realizaba a trav├®s del puente de la Almozara y la estaci├│n del Norte. Las obras finalizaron en julio de 1968, y con esta nueva ruta, el antiguo trazado inici├│ su cuenta atr├ís para ser desmantelado como infraestructura ferroviaria. La captura se ha realizado a la altura del camino del Vado que, en primer plano, transita de derecha a izquierda hacia el G├íllego. En este punto se est├í emplazando la empresa Prefabricados Moldeados S.A. (Premolsa). Al fondo, y al otro lado del Ebro, la huerta de las Fuentes, desde donde proviene el despejado amojonamiento que indica el trazado de este nuevo enlace ferroviario. Fuente visual: Arxiu Nacional de Catalunya', 1966, 1966, 1966, 'Anos 60', 'EL RABAL', 41.65688600, -0.85236000, '0101000020E6100000D8648D7A8846EBBFA29927D714D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31069263344.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31069263344.webp', 'https://www.flickr.com/photos/zaragozaantigua/31069263344/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22462, 'Calle Sobrarbe 1968', 'Febrero de 1968. Entrada del colegio C├índido Domingo en la calle del Sobrarbe 8, junto a la iglesia de Altab├ís (izquierda). Edificio de Ricardo Magdalena de 1909 que fue derribado en 1970 para construir el actual. Fuente visual: www.facebook.com/photo.php?fbid=425484417477116&set=a...', 1968, 1968, 1968, 'Anos 60', 'EL RABAL', 41.65923500, -0.87415500, '0101000020E6100000F05014E813F9EBBF75B0FECF61D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32491020753.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32491020753.webp', 'https://www.flickr.com/photos/zaragozaantigua/32491020753/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22920, 'Calle de Balbino Orensanz c.1980', 'Imagen capturada en la calle de Balbino Orensanz, antes del Colector, con una escena flanqueada a la izquierda por la f├íbrica de Amado Laguna Rins y a la derecha por las dos veteranas y gemelas naves industriales que confrontaban con ella, seguidas por el colegio nacional de EGB "La Jota" activo desde 1972. Tras ├®l, la calle de Joaqu├¡n Numancia, los dos bloques promovidos por "Hogar Cristiano" y m├ís al fondo los bloques recayentes a la avenida de la Jota. En primer t├®rmino y hacia la derecha, la calle del pintor Manuel Viola.', 1980, 1980, 1980, 'Anos 80', 'EL RABAL', 41.65939000, -0.85900400, '0101000020E61000000B43E4F4F57CEBBF9CA73AE466D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27717343550.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27717343550.webp', 'https://www.flickr.com/photos/zaragozaantigua/27717343550/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23250, 'Calle de Jes├║s c.1935', 'Imagen capturada en el gran lavadero al aire del Puente del Pilar centrado en el acceso, al fondo, desde la calle de Jes├║s, con vista de las parcelas de los n├║meros 33, 35 y 37. En primer t├®rmino, la pila de lavar ropa con jab├│n de "tajo". A la izquierda, pila de lavar a cubierto. A la derecha, alameda y arranque de la extensa zona de los tendederos. Este lavadero se abastec├¡a de uno de los brazales de Jope de la acequia del Rabal.', 1935, 1935, 1935, 'Anos 30', 'EL RABAL', 41.65782700, -0.87036500, '0101000020E610000044A852B307DAEBBF80B6D5AC33D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15060928093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15060928093.webp', 'https://www.flickr.com/photos/zaragozaantigua/15060928093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23666, 'Calle de Jes├║s c.1972', 'Imagen capturada junto a la achaflanada esquina del final de la calle de la Estaci├│n (en primer plano), con vista parcial del primer tramo de la calle de Jes├║s, donde destaca el antiguo y enorme cuartel de la Guardia Civil sito en el moderno n┬║ 8 (antiguo 16), caracter├¡stico por su entrante zona aprovechada como aparcamiento por los menudos coches de la ├®poca. A la izquierda, la esquina de ingreso a la calle de Funes. Inmediato, un llamativo contraste de firmes: adoquinado desde la calle de la Estaci├│n, asfaltado, en la calle de Jes├║s. Fuente visual: "Asociaci├│n de Vecinos Barrio de Jes├║s. 30 a├▒os de Historia".', 1972, 1972, 1972, 'Anos 70', 'EL RABAL', 41.65814200, -0.87139400, '0101000020E6100000ACC77DAB75E2EBBFE00F3FFF3DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30467393542.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30467393542.webp', 'https://www.flickr.com/photos/zaragozaantigua/30467393542/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23950, 'Cine Norte 1960', 'En la calle de Jes├║s, del barrio del mismo nombre. Esta sala se inaugur├│ el 14 de octubre de 1953 con la proyecci├│n de la pel├¡cula "El s├®ptimo cielo" . Fue clausurada en noviembre de 1981 y el edificio derribado en febrero de 2007. Fuente visual: Asociaci├│n de Vecinos del Barrio de Jes├║s.', 1960, 1960, 1960, 'Anos 60', 'EL RABAL', 41.65802800, -0.87099200, '0101000020E6100000F67B629D2ADFEBBF18EDF1423AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14700983029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14700983029.webp', 'https://www.flickr.com/photos/zaragozaantigua/14700983029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24039, 'Marqu├®s de la Cadena 2003', 'Imagen, desde altura, de la paloma de la paz formada por alumnado y padres de los colegios Hilari├│n Gimeno, la Pur├¡sima y San Antonio, y la Asociaci├│n de Vecinos Barrio de Jes├║s, durante las movilizaciones sociales contra la implicaci├│n expl├¡cita de Espa├▒a en la segunda Guerra de Irak ("el tr├¡o de las Azores", Bush, Blair, Aznar). El solar donde tuvo lugar este acto, adem├ís, estaba siendo reivindicado para la construcci├│n de un nuevo equipamiento educativo p├║blico, que luego ser├¡a denominado CEIP Marie Curie, con entrada principal por la calle Molino de las Armas (a la izquierda). Al fondo, densa circulaci├│n rodada por la calle del Marqu├®s de la Cadena, y detr├ís, los bloques de viviendas junto a la calle M┬¬ Pilar de las Heras Dopereiro. Fuente visual: "Asociaci├│n de Vecinos Barrio de Jes├║s. 30 a├▒os de Historia".', 2003, 2003, 2003, 'Siglo XXI', 'EL RABAL', 41.65972100, -0.86402400, '0101000020E6100000FBB0DEA815A6EBBF01BEDBBC71D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30246407290.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30246407290.webp', 'https://www.flickr.com/photos/zaragozaantigua/30246407290/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24178, 'Choque de trenes 1913', 'Choque de trenes a la salida de la Estaci├│n del Norte en la curva que llevaba al t├║nel de San L├ízaro. Se trata de un tren correo que colision├│ con una locomotora. Al fondo, c├║pula mayor de la Bas├¡lica del Pilar.', 1913, 1913, 1913, 'Anos 10', 'EL RABAL', 41.65906100, -0.87288800, '0101000020E61000006344A2D0B2EEEBBFD788601C5CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15282120374.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15282120374.webp', 'https://www.flickr.com/photos/zaragozaantigua/15282120374/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24180, 'Estaci├│n del Norte 1930', 'Vista del Arrabal zaragozano, con la Estaci├│n del Norte ferroviaria presidiendo el entorno. Fuente: Zaragoza 1908-2008. FCC.', 1930, 1930, 1930, 'Anos 30', 'EL RABAL', 41.65968100, -0.87189300, '0101000020E6100000009013268CE6EBBF7365506D70D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15523934069.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15523934069.webp', 'https://www.flickr.com/photos/zaragozaantigua/15523934069/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24181, 'Estaci├│n del Norte 1935', 'Plano de la zona de la Estaci├│n del Norte realizado por el Instituto Geogr├ífico y Catastral, coloreado posteriormente. Fuente visual: eszaragoza.blogspot.com.es/2014/02/la-estacion-del-norte-...', 1935, 1935, 1935, 'Anos 30', 'EL RABAL', 41.65968100, -0.87189300, '0101000020E6100000009013268CE6EBBF7365506D70D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15659723188.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15659723188.webp', 'https://www.flickr.com/photos/zaragozaantigua/15659723188/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24196, 'Estaci├│n del Norte c.1920', 'Acceso a la estaci├│n ferroviaria del Norte o del Arrabal. Fuente: Foto Jes├║s Corm├ín. AMZ.', 1920, 1920, 1920, 'Anos 20', 'EL RABAL', 41.65968100, -0.87189300, '0101000020E6100000009013268CE6EBBF7365506D70D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24797241492.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24797241492.webp', 'https://www.flickr.com/photos/zaragozaantigua/24797241492/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24214, 'Arrabal 1935', 'Imagen capturada junto a las v├¡as ferroviarias de la curva que hacia la derecha se dirigen a la estaci├│n del Arrabal. Circula una locomotora vaporosa, posiblemente una "Chaleco". En primer t├®rmino, el convento de la terciarias franciscanas de Altab├ís con ingreso desde la calle del Sobrarbe. Hacia el fondo, el puente de Piedra y el templo del Pilar con andamios sobre sus c├║pulas orientales, entre ellas la de la capilla de la Virgen.', 1935, 1935, 1935, 'Anos 30', 'EL RABAL', 41.65882900, -0.87310100, '0101000020E61000004F5B238271F0EBBF0454388254D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50978794727.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50978794727.webp', 'https://www.flickr.com/photos/zaragozaantigua/50978794727/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24496, 'Harinas Gav├¡n 1912', 'Cabecera de factura de "La Moderna" F├íbrica de Harinas Francisco Gav├¡n y Compa├▒├¡a, con sede en "Carretera del Puente del G├íllego n├║meros 239 y 240, frente a la estaci├│n del Norte". La ilustraci├│n reproduce sus instalaciones, en la que ser├í avenida de Catalu├▒a, en la manzana entre las calles de la Estaci├│n ( a la derecha), y del Norte (a la izquierda). Esta f├íbrica formaba parte, junto con las de Sol├íns, y Guiu, del n├║cleo molinero del Arrabal en la segunda d├®cada del siglo XX, y hay constancia de su actividad desde 1912, y hasta 1922. Fuente: www.todocoleccion.net', 1912, 1912, 1912, 'Anos 10', 'EL RABAL', 41.65985700, -0.87047700, '0101000020E61000003672DD94F2DAEBBFB284B53176D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29975587684.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29975587684.webp', 'https://www.flickr.com/photos/zaragozaantigua/29975587684/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24780, 'Calle de Jes├║s 1977', 'Imagen del desemboque de la calle de Jes├║s, desde la izquierda, en la avenida del Puente del Pilar, con una interesante panor├ímica de las antiguas y simpares viviendas impares que aqu├¡ se levantaban, hasta el inmediato 43 que, aun con una altura menos, ten├¡a una envidiable visual del entorno por su esquinera ubicaci├│n, y adem├ís era un "Bar-Churrer├¡a". Al fondo, a la izquierda, sesenteros y sobresalientes edificios de la calle de Valima├▒a, recayentes a la plaza de Jes├║s, heraldos del futuro porvenir. La mutaci├│n de esta manzana entre las calles de Jes├║s, Valima├▒a, y Corral├®, ha sido notable, entre derribos, nuevas construcciones, y un buen repertorio de solares. De las parcelas de la imagen, no queda ni una. Y pensar que esta calle lleg├│ a tener incluso ├írboles, cuando en la acera de enfrente estaban los grandes lavaderos y tendederos que fueran de Modesto Andr├®s. Fuente visual: amable aportaci├│n personal de Pablo Vald├®s.', 1977, 1977, 1977, 'Anos 70', 'EL RABAL', 41.65778100, -0.86958100, '0101000020E61000009F2287889BD3EBBF1077F52A32D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26939145335.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26939145335.webp', 'https://www.flickr.com/photos/zaragozaantigua/26939145335/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24781, 'Calle Sobrarbe 1977', 'Crepuscular, despejada e ins├│lita imagen del tramo de la calle de Sobrarbe en torno a la iglesia parroquial de N┬¬ S┬¬ de Altab├ís, cuya nueva planta fue inaugurada en 1892. Al fondo, a la derecha, el cimborrio del metropolitano templo de El Salvador, una filigrana de Mahoma Ram├¡, anuncia que, aun con el Ebro de por medio, esta parte del antiguo Arrabal de Altab├ís formaba parte de la ciudad desde muchos siglos ha, con edificios tan representativos como el mercedario convento de San L├ízaro, y los franciscanos de N┬¬ S┬¬ de Jes├║s, y el de Santa Isabel. Pese a la cercan├¡a, la natural trinchera fluvial marc├│ un devenir diferenciado, aut├│nomo. No pod├¡a ser de otra forma, con un r├¡o tan irregular en su caudal, tan mediterr├íneo, como el Ebro, pese a los delirios de quien se lo imagina ub├®rrimo en nautas y nav├¡os. Sus monumentales salidas de madre, siempre noticia, eclipsaban con sus tremendas afecciones las largas temporadas en que, durante el resto del a├▒o, se pod├¡a vadear con relativa facilidad. Eso del dragado es una cosa muy reciente. En la luminosa imagen, la fachada de los pares nos alumbra, en primer t├®rmino, una casona que ya no est├í, muestra de la arquitectura popular de esta veterana zona. A su lado, perduran el elaborado n┬║ 16, el humild├¡simo n┬║ 14, el n┬║ 12 de la iglesia, y el n┬║ 10. Luego, el colegio "C├índido Domingo", con su nueva f├íbrica de 1970, que sustituy├│ a la inaugurada en 1909 con dise├▒o de Ricardo Magdalena. Despu├®s, el convento de Santa Isabel reconstruido tras el asedio de 1808, que llegaba hasta la antigua plaza de san L├ízaro. Tras pasar las v├¡as del ferrocarril, quedaba el cuartel de ese mismo nombre. Fuente visual: amable aportaci├│n personal de Pablo Vald├®s.', 1977, 1977, 1977, 'Anos 70', 'EL RABAL', 41.65941600, -0.87396900, '0101000020E61000006AF816D68DF7EBBFC53A55BE67D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27257313276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27257313276.webp', 'https://www.flickr.com/photos/zaragozaantigua/27257313276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24784, 'Arrabal c.1967', 'Esplendorosa locomotoca anglosajona "Avonside" que, compuesta all├í por 1865, segu├¡a traqueteando de forma funcional un siglo despu├®s, en este caso desde la estaci├│n del Norte (al fondo, inaugurada tambi├®n al principio de esa decimon├│nica d├®cada) en direcci├│n al enlace ferroviario hacia Alsasua, durante una tarde luminosa, con la tripulaci├│n sonriendo al objetivo. A la derecha, asoma el remate con reloj del edificio de de las oficinas principales de la Maquinista y Fundiciones del Ebro S.A., junto a la avenida de Catalu├▒a. Fuente visual: Javier Santamar├¡a, en www.spanishrailway.com/', 1967, 1967, 1967, 'Anos 60', 'EL RABAL', 41.65940000, -0.87259600, '0101000020E610000073DA53724EECEBBFBF7D1D3867D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29988346264.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29988346264.webp', 'https://www.flickr.com/photos/zaragozaantigua/29988346264/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24801, 'Calle Alfonso Zapater 2009', 'Vista del solar entre las calles de Alfonso Zapater Cerd├ín (desde donde est├í tomada la foto), Mariano Cebollero (derecha), Jorge S├ínchez Candial (al fondo) y Antonio Royo (izquierda, fuera de plano). M├ís al fondo, los bloques de la calle Nobleza Baturra, en direcci├│n hacia el Ebro. Aqu├¡ se construir├í en 2011 el Colegio P├║blico de Infantil y Primaria Vadorrey-Les All├®es. Fuente visual: Heraldo de Arag├│n.', 2009, 2009, 2009, 'Siglo XXI', 'EL RABAL', 41.65673400, -0.85654900, '0101000020E6100000F67CCD72D968EBBFEC1516DC0FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33105317192.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33105317192.webp', 'https://www.flickr.com/photos/zaragozaantigua/33105317192/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24819, 'Avenida del puente del Pilar 1992', 'Imagen centrada en el antiguo inmueble del n┬║ 19 de la avenida del Puente del Pilar, esquinero con el principio de la calle de Jacinto Corral├®. Esta calle recibi├│ su nombre de la hom├│nima Torre pegada al sur del convento de Jes├║s por donde fue trazada cuando la reparcelaci├│n de esa zona en los a├▒os 20 del pasado siglo XX. Esta vivienda se construy├│ en esa ├®poca, y ser├¡a derribada a├▒os despu├®s de tomada esta fotograf├¡a, como su vecina del n┬║ 21 a la derecha, para ensanchar la avenida.', 1992, 1992, 1992, 'Anos 90', 'EL RABAL', 41.65818800, -0.86932500, '0101000020E6100000E10B93A982D1EBBF514F1F813FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50199796771.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50199796771.webp', 'https://www.flickr.com/photos/zaragozaantigua/50199796771/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24829, 'Calle del Sobrarbe c.1900', '├ôleo del pintor navarro Leopoldo Albesa Membrado que representa una escena urbana localizada en la calle del Sobrarbe vertebradora del Arrabal zaragozano en su ascenso hacia la carretera de Huesca. A la izquierda, el largo tramo de este vial comprendido entre el convento de Altab├ís al fondo y el luminoso ingreso al patio de carros de la estaci├│n del Norte. A la derecha, el tramo articulado por el camino de Juslibol y las calles del Horno, de Jorge Ibort y de Villacampa. Al fondo y en la margen derecha, la barroca torre de la Seo emerge tras el edificio del Seminario conciliar.', 1900, 1900, 1900, 'Anos 1900', 'EL RABAL', 41.65911900, -0.87426300, '0101000020E6100000884A2366F6F9EBBF0B96EA025ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54588999160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54588999160.webp', 'https://www.flickr.com/photos/zaragozaantigua/54588999160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24752, 'Calle Horno 1977', 'Vista de la estrecha calle del Horno de Zaragoza. Al fondo, la calle de Manuel Lacruz. A la espalda, la calle del Sobrarbe. Fuente: La orilla izquierda del Ebro zaragozano, Mar├¡a Carmen Faus, 1988.', 1977, 1977, 1977, 'Anos 70', 'EL RABAL', 41.65938100, -0.87496900, '0101000020E61000003F7100FDBEFFEBBF494DBB9866D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18998507100.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18998507100.webp', 'https://www.flickr.com/photos/zaragozaantigua/18998507100/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24821, 'Calle de Mariano Gracia c.1992', 'Imagen capturada desde la calle de Manuel Lacruz (originalmente del Rosario) y centrada en los seriados inmuebles del siglo XVII correspondientes a los n├║meros 1, 3 y 5 del principio de la calle de Mariano Gracia, antigua de Cantarranas. A finales de d├®cada, estos edificios fueron rehabilitados e integrados al actual n┬║ 24-28 de la calle de Sixto Celorrio. Al fondo, el setentero bloque del n┬║ 1, 3, 5 de la calle de Gregorio Garc├¡a Arista, radical contraste con el caser├¡o tradicional de esta zona del casco hist├│rico del Arrabal.', 1992, 1992, 1992, 'Anos 90', 'EL RABAL', 41.65961500, -0.87531200, '0101000020E6100000B77BB94F8E02ECBFBC79AA436ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50213249743.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50213249743.webp', 'https://www.flickr.com/photos/zaragozaantigua/50213249743/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24798, 'Vista a├®rea Norte c.1968', 'Vista a├®rea parcial del norte de Zaragoza, con el Pilar abajo y la margen izquierda al fondo. Fuente visual: foto Pedro Marco.', 1968, 1968, 1968, 'Anos 60', 'EL RABAL', 41.66138300, -0.87986300, '0101000020E6100000FDBB3E73D627ECBFB090B932A8D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32876805253.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32876805253.webp', 'https://www.flickr.com/photos/zaragozaantigua/32876805253/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20935, 'Acequia de Santa B├írbara 1769', '"Plano demonstrativo del curso que tiene y lleva la Acequia de Santa B├írbara, con los riegos dependientes de ella, partida de Val de Espartera y dem├ís que en el mismo se expresan". Orientado de sur a norte, el plano incluye el recorrido de la acequia de Santa B├írbara, junto a los terrenos de Valdespartera. Fuente: AHPZ.', 1769, 1769, 1769, 'Siglo XIX', 'CASABLANCA', 41.62839000, -0.93496200, '0101000020E61000008B16A06D35EBEDBF159161156FD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31114453490.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31114453490.webp', 'https://www.flickr.com/photos/zaragozaantigua/31114453490/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21082, 'Esclusas Casablanca c.1878', 'Imagen de las ilustradas esclusas de San Carlos, o de Casablanca, en el Canal Imperial. La captura se ha realizado desde el puente que salvaba el Canal para dar paso a la carretera de Zaragoza a Valencia, y la l├¡nea de ferrocarril a Caminreal. Los edificios del fondo, una antigua harinera reconvertida en dependencias militares, unos a├▒os antes de ser habilitados en convento de los padres Pasionistas. Fuente visual: "Zaragoza dos milenios de agua", Carlos Bl├ízquez. Aunque esta imagen figura como "Archivo Coyne", su autor fue Venancio Villas Langa.', 1878, 1878, 1878, 'Siglo XIX', 'CASABLANCA', 41.62833800, -0.90888200, '0101000020E6100000CE893DB48F15EDBFC26A2C616DD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26089781651.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26089781651.webp', 'https://www.flickr.com/photos/zaragozaantigua/26089781651/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21120, 'Embarcadero Casablanca 1880', 'Imagen de las gradas que conformaban el antiguo embarcadero recreativo de Casa Blanca, inmediatas al puente de piedra por el que la carretera de Zaragoza a Valencia por Teruel salvaba el Canal Imperial, justo a la izquierda, fuera de plano. Las barcazas de transporte utilizaban las esclusas, luego auxiliadas por las caballer├¡as que por el camino de sirga, a la derecha, tiraban de ellas. Al fondo, la Fuente de los Incr├®dulos en su original ubicaci├│n, y construcciones junto a la carretera de Teruel. Unos pocos a├▒os despu├®s se habilitar├¡a otro paso sobre el Canal para el camino de hierro del ferrocarril de Cari├▒ena a Zaragoza, cuyo trazado fue establecido por detr├ís de la fuente. Fuente visual: Foto Venancio Villas Langa, AHPZ.', 1880, 1880, 1880, 'Siglo XIX', 'CASABLANCA', 41.62806000, -0.90801200, '0101000020E610000086048C2E6F0EEDBF7FF6234564D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30919041124.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30919041124.webp', 'https://www.flickr.com/photos/zaragozaantigua/30919041124/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21663, 'Valdespartera 1920', 'Imagen capturada a finales del mes de septiembre durante el concurso de tractores organizado por el Consejo provincial de Fomento y la cooperaci├│n de la Diputaci├│n provincial, el Ayuntamiento y todas las entidades locales de car├ícter agr├¡cola en el entorno del campo de Valdespartera. Si bien no fue la primera prueba de este tipo, s├¡ fue la m├ís importante realizada hasta la fecha por el n├║mero de marcas inscritas (hasta 34). Al objeto de facilitar el acceso de p├║blico asistente, la organizaci├│n dispuso un "cami├│n autom├│vil" que cada hora part├¡a desde la plaza de la Constituci├│n hasta el lugar del concurso. En la escena, posiblemente un tractor-tanque Holt 23/40 de la marca estadounidense Caterpillar realiza una prueba de arada bajo la atenta mirada de los miembros del jurado.', 1920, 1920, 1920, 'Anos 20', 'CASABLANCA', 41.61982400, -0.92727100, '0101000020E610000056EF703B34ACEDBF51A3906456CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54960928426.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54960928426.webp', 'https://www.flickr.com/photos/zaragozaantigua/54960928426/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21863, 'Casablanca 1934', 'Imagen de una de las dos terrazas del bar restaurant El Caser├¡o Aragon├®s, muy frecuentado establecimiento de restauraci├│n ubicado en el barrio de Casablanca, cerca de las hom├│nimas esclusas, junto a la carretera de Valencia y el Canal Imperial. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CASABLANCA', 41.62820400, -0.90766900, '0101000020E61000000DFAD2DB9F0BEDBFB29B19FD68D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36328624161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36328624161.webp', 'https://www.flickr.com/photos/zaragozaantigua/36328624161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21876, 'Esclusas Casablanca 1935', '"Doble resclosa de Casablanca, al canal Imperial, prop de Saragossa". Imagen capturada desde el antiguo puente de la carretera de Zaragoza a Valencia, con una interesante visual, en primer t├®rmino, del met├ílico puente ferroviario, el complejo de las esclusas de Casablanca, donde se salva un importante desnivel del Canal Imperial que El├®ctricas Reunidas aprovechaba para una f├íbrica de electricidad que all├¡ ten├¡a. Al fondo, al otro lado del Canal Imperial, el convento y colegio de los PP. Pasionistas de Casablanca, Fuente visual: Fotograf├¡a de S. Gos├® en Arxiu Nacional de Catalunya.', 1935, 1935, 1935, 'Anos 30', 'CASABLANCA', 41.62817000, -0.90843200, '0101000020E6100000D57954FCDF11EDBF062AE3DF67D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40560874800.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40560874800.webp', 'https://www.flickr.com/photos/zaragozaantigua/40560874800/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21911, 'Casablanca 1938', 'Imagen centrada en el edificio de la falangista emisora "Radio Zaragoza E.A.J. 101" junto al Canal Imperial de Arag├│n y en la parte alta de Casablanca, el d├¡a de su solemne inauguraci├│n cuando desde sus micr├│fonos se radi├│ el "hist├│rico" discurso del "Caudillo" Francisco Franco con motivo del I aniversario del Decreto de unificaci├│n de FET y de la JONS, escuchado en Zaragoza por una gran reuni├│n de "73.457" falangistas y "la poblaci├│n toda" de la ciudad, concentrada en el Campo de la Victoria. En primer t├®rmino, uno de los miembros de la guardia personal del "General├¡simo", con su reconocible "turbante blanco y capa roja".', 1938, 1938, 1938, 'Anos 30', 'CASABLANCA', 41.63570800, -0.91619900, '0101000020E6100000CA17B4908051EDBF1DE736E15ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51884261905.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51884261905.webp', 'https://www.flickr.com/photos/zaragozaantigua/51884261905/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22064, 'Isabel la Cat├│lica 1956', 'Vista a├®rea de Isabel la Cat├│lica desde las esclusas de Casablanca y el Canal Imperial (en primer t├®rmino). A la izquierda, a├║n quedan rastros del antiguo trazado del ferrocarril de Cari├▒ena por Casablanca. En el centro, construcci├│n del Hospital Militar que supondr├í el abandono de las instalaciones del recinto junto a la Iglesia de Santiago el Mayor.', 1956, 1956, 1956, 'Anos 50', 'CASABLANCA', 41.63074200, -0.90444200, '0101000020E6100000641F645930F1ECBF581B6327BCD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15056716205.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15056716205.webp', 'https://www.flickr.com/photos/zaragozaantigua/15056716205/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22288, 'V├¡a de la Hispanidad 1965', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 02/04/1965. "Inauguraci├│n de la V├¡a Hispanidad." El presidente del "Instituto de Cultura Hisp├ínica", Gregorio Mara├▒├│n Moya, fue nombrado "caballero del Pilar" en la capilla de la Virgen por el arzobispo Cantero. Aprovechando viaje, inaugur├│ la avenida de la "V├¡a de la Hispanidad", hasta entonces "carretera de Los Enlaces", pues el Instituto que presid├¡a puso el dinero para las monumentales placas que, como la de la imagen, se├▒alaban la nueva v├¡a. En la imagen, inauguraci├│n junto a una de las placas, donde la nueva carretera de Valencia (desde 1975, V├¡a Ib├®rica) se abre a la izquierda hacia la V├¡a de la Hispanidad.', 1965, 1965, 1965, 'Anos 60', 'CASABLANCA', 41.63222000, -0.90573900, '0101000020E61000009BC6F65AD0FBECBF45F0BF95ECD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15206601647.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15206601647.webp', 'https://www.flickr.com/photos/zaragozaantigua/15206601647/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22305, 'Canal Imperial 1967', 'Acampada libre en Valdefierro, a orillas del Canal Imperial. Esta barriada deriva su nombre de la zona del Brazal de Fierro, que estaba surtida por el riego hom├│nimo de agua procedente del Huerva derivado de la acequia del Medio. El puente acueducto sobre el Canal de la imagen, llamado de Enmedio, serv├¡a desde finales del siglo XVIII para dar continuidad a ese riego. El campin municipal de Casablanca se encontraba a espaldas del fot├│grafo. Fuente visual: Ediciones Arribas, en www.facebook.com/photo.php?fbid=400711503426853&set=o...', 1967, 1967, 1967, 'Anos 60', 'CASABLANCA', 41.63489800, -0.92607600, '0101000020E61000002F89B3226AA2EDBFDD25715644D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15619035777.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15619035777.webp', 'https://www.flickr.com/photos/zaragozaantigua/15619035777/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22328, 'Parroquia de San Vicente de Pa├║l 1967', 'El Arzobispo Cantero dio en 1965 el placet para que una antigua capilla-ermita del Canal Imperial de Arag├│n fuera cedida y se convirtiera en la provisional iglesia parroquial de San Vicente de Pa├║l (Padres Pa├║les) de Casablanca. Con una grey estimada en 4.000 almas, estuvo activa hasta que las obras de ensanchamiento para el tr├ífico rodado de la antigua carretera de Valencia, que en este tramo ser├í denominada "V├¡a ib├®rica", requirieron su necesaria demolici├│n, y el retranqueamiento de la Fuente de los Incr├®dulos, que se tuvo que apartar de su original ubicaci├│n, para no molestar. Esta modesta capilla hab├¡a sido construida en formas neocl├ísicas con ocasi├│n de la llegada de las aguas del Canal Imperial a Zaragoza en 1787, bajo la advocaci├│n de N┬¬ S┬¬ del Pilar, y ofrec├¡a ceremonias los d├¡as festivos. Fuese, y luego ya no hubo nada. En la imagen, fachadita de la parroquia, con su exclusiva espada├▒a, capturada desde una tranquila y adoquinada carretera de Valencia. A la izquierda, a unas decenas de metros, la Fuente de los Incr├®dulos en su original ubicaci├│n. A la derecha, la calle Embarcadero, antigua de La Ermita. Fuente visual: pauleszaragoza.org/', 1967, 1967, 1967, 'Anos 60', 'CASABLANCA', 41.62920500, -0.90765900, '0101000020E61000002A711DE38A0BEDBF66BD18CA89D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17715692140.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17715692140.webp', 'https://www.flickr.com/photos/zaragozaantigua/17715692140/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22351, 'Stadium Casablanca 1969', 'Barcas a la entrada del Stadium Casablanca de Acci├│n Cat├│lica de Zaragoza, en el Canal Imperial de Arag├│n. Fuente: "Zaragoza viva" (1969)', 1969, 1969, 1969, 'Anos 60', 'CASABLANCA', 41.62447300, -0.90662400, '0101000020E61000003999B8551003EDBF151E34BBEECF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20558391611.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20558391611.webp', 'https://www.flickr.com/photos/zaragozaantigua/20558391611/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22457, 'Isabel la Cat├│lica 1965', 'Imagen volandera centrada en la primera fase constructiva del proyecto de torres de viviendas en la confluencia del paseo de Isabel la Cat├│lica con el enlace de carreteras. A su izquierda, el murete que delimita el nuevo Hospital Militar. A su derecha, el Colegio-Residencia de Nuestra Se├▒ora del Pilar para Hu├®rfanos e Hijos del Magisterio. Al otro lado del paseo, vista parcial del convento de Jerusal├®n, y los campos de herb├íceas y torres agr├¡colas en el feraz entorno del Seminario. Fuente visual: Arxiu Nacional de Catalunya', 1965, 1965, 1965, 'Anos 60', 'CASABLANCA', 41.63242200, -0.90360200, '0101000020E6100000C634D3BD4EEAECBFADA23F34F3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31800429245.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31800429245.webp', 'https://www.flickr.com/photos/zaragozaantigua/31800429245/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22478, 'Ctra. de Valencia c.1965', 'Imagen capturada en la carretera de Zaragoza a Valencia, en el tramo previo a la fuente de los Incr├®dulos y las esclusas de Casablanca, con una vista parcial de los edificios de los n├║meros 83 a 86, ubicados frente a la antigua casa de San Carlos y la capilla-ermita de Nuestra Se├▒ora del Pilar. A la derecha, un pedazo de la fachada de la casa de Miguel Rived recayente a la carretera de Valencia. Ninguna de estas estructuras perdura. Fuente visual: Nuria As├¡n Garc├¡a, "Recuerdos de Casablanca", Ediciones 94, (2015).', 1965, 1965, 1965, 'Anos 60', 'CASABLANCA', 41.62941500, -0.90696000, '0101000020E610000012F758FAD005EDBF514EB4AB90D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34950276292.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34950276292.webp', 'https://www.flickr.com/photos/zaragozaantigua/34950276292/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22479, 'Calle del Embarcadero c.1965', 'Imagen capturada en la calle del Embarcadero del barrio de Casablanca, y orientada hacia su arranque, al fondo, por donde pasa la carretera de Zaragoza a Valencia. En el lado izquierdo de la calle, donde aparece estacionado un joven vecino sobre una motoneta Lambretta, muros de la antigua casa de San Carlos. En el lado derecho, y fuera de plano, la dieciochesca capilla-ermita de Nuestra Se├▒ora del Pilar, que proyecta su leve sombra al atardecer. El firme de la calle, terrestre a m├ís no poder. Fuente visual: Nuria As├¡n Garc├¡a, "Recuerdos de Casablanca", Ediciones 94, (2015).', 1965, 1965, 1965, 'Anos 60', 'CASABLANCA', 41.62964000, -0.90752900, '0101000020E61000009E7DE5417A0AEDBF7120240B98D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35144364095.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35144364095.webp', 'https://www.flickr.com/photos/zaragozaantigua/35144364095/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22524, 'V├¡a de la Hispanidad 1970', 'Junto a la estaci├│n de servicio de Casablanca, a la derecha de la imagen, un reba├▒o de ovejas, a rueda de las cabras, cruza por la V├¡a de la Hispanidad, reciente denominaci├│n de la antigua carretera de Los Enlaces. A la izquierda, el nuevo pol├¡gono de la Gran V├¡a, redenominado de la Romareda. La imagen capta un momento de transici├│n pactada entre el mundo rural que caracteriz├│ esta periferia de la ciudad, con el moderno de los altos bloques y las carreteras para veh├¡culos a gran velocidad. Un cami├│n procedente de la gasolinera espera paciente. Por este entorno cruzaba anta├▒o la antigua l├¡nea ferrovaria de Cari├▒ena, hasta 1933. A la derecha, la calle de La V├¡a recuerda el paso de este tren de v├¡a estrecha. Al fondo, una glorieta, actual rotonda de Toulouse, en la confluencia del paseo de Isabel la Cat├│lica, la V├¡a Ib├®rica y la propia V├¡a de la Hispanidad.', 1970, 1970, 1970, 'Anos 70', 'CASABLANCA', 41.63382400, -0.90816300, '0101000020E6100000F0FD0DDAAB0FEDBFBFB5132521D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14665038980.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14665038980.webp', 'https://www.flickr.com/photos/zaragozaantigua/14665038980/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22528, 'Almenara del Pilar 1970', 'Desde 1961, el "Paseo de los Reyes de Arag├│n" comenzaba en el Rinc├│n de Goya y desembocaba en la Carretera de Valencia, donde las esclusas de Casablanca. La imagen recoge un despejado pedazo de este Paseo, en la pronunciada y cerrada curva donde la Almenara de N┬¬ S┬¬ del Pilar se├▒ala el punto donde se cruzan el Canal Imperial y el r├¡o Huerva. El Puente de un ojo se├▒ala el cauce del Canal por encima del r├¡o. A su izquierda, la Almenara y, escalonado, el aporte de agua del Canal al r├¡o. A la derecha, el Paseo asciende poco a poco hasta la Fuente de los Incr├®dulos y las Esclusas. Detalle de la carretera que deriva y que conducir├í pronto a la Urbanizaci├│n "Fuentes Claras". Todo el entorno est├í mucho menos poblado de vegetaci├│n, ├írboles, y exclusividad residencial. Al fondo, el cuartel de Valdespartera. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1970, 1970, 1970, 'Anos 70', 'CASABLANCA', 41.62225100, -0.90475700, '0101000020E61000006077BAF3C4F3ECBF9F73B7EBA5CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14704752439.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14704752439.webp', 'https://www.flickr.com/photos/zaragozaantigua/14704752439/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22805, 'Pasionistas 1976', 'Imagen a├®rea del moderno complejo formado por la residencia de los padres Pasionistas y la iglesia parroquial de Santa Gema construido junto a la Colonia de Nuestra Se├▒ora de las Nieves y con ingreso por la calle de la Sagrada Familia, en primer t├®rmino. A la izquierda y tras la calle de Marcelino ├ülvarez, instalaciones de la fundici├│n de Ebroacero. Al fondo, la calle del Greco. A la derecha, vista tangencial del antiguo convento de los Pasionistas, derribado un par de a├▒os despu├®s, junto al Canal Imperial de Arag├│n.', 1976, 1976, 1976, 'Anos 70', 'CASABLANCA', 41.62878000, -0.91166100, '0101000020E6100000AC3C81B0532CEDBF7F30F0DC7BD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49904753401.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49904753401.webp', 'https://www.flickr.com/photos/zaragozaantigua/49904753401/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22806, 'Pasionistas 1976', 'Imagen a├®rea centrada en el moderno complejo formado por la residencia de los padres Pasionistas y la iglesia parroquial de Santa Gema construido junto a la Colonia de Nuestra Se├▒ora de las Nieves y con ingreso por la calle de la Sagrada Familia, a la derecha. Contrasta el antiguo convento de los Pasionistas, que ser├¡a derribado un par de a├▒os despu├®s. En primer t├®rmino, la calle de Marcelino ├ülvarez. Hacia el fondo, la arboleda ribera del Canal Imperial de Arag├│n, y tras ├®l el entorno edilicio de la calle de la Ermita, la del Embarcadero y la del Prado, en el barrio de Casablanca.', 1976, 1976, 1976, 'Anos 70', 'CASABLANCA', 41.62873900, -0.91174700, '0101000020E61000004F3C670B082DEDBF215C01857AD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49966610228.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49966610228.webp', 'https://www.flickr.com/photos/zaragozaantigua/49966610228/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22826, 'Cristo legionario 1973', 'Imagen del artista pl├ístico I├▒aki Rodr├¡guez Ruiz "I├▒aki" (Bilbao, 1940-Zaragoza, 2018) ultimando la imagen del "Cristo de la Buena Muerte" encargado por la Hermandad de Caballeros Legionarios que habr├¡a de formar parte central del "paso" de Semana Santa del Sant├¡simo Cristo de la Buena Muerte. La captura se ha realizado en los talleres de la Instituci├│n Sindical de Formaci├│n Profesional "Virgen del Pilar", dos de cuyos alumnos y profesores aparecen aqu├¡ colaborando en la faena. Realizado en hierro forjado, este bulto redondo se montar├¡a luego sobre una ballesta, una alabarda y un arcabuz, elementos todos ellos en madera integrantes del emblema de la Legi├│n Espa├▒ola, y ser├¡a bendecido solemnemente por el arzobispo Pedro Cantero Cuadrado. Unos d├¡as despu├®s se program├│ la participaci├│n de este "paso" con su cofrad├¡a en las procesiones de Semana Santa, aunque una carta del arzobispo recomend├│ suprimir los artefactos b├®licos (las referidas ballesta, alabarda y arcabuz) al objeto de evitar que "pudieran dar lugar a err├│neas interpretaciones"... Como buenos cat├│licos, desde la Hermandad de Caballeros Legionarios se procedi├│ a suprimir esos elementos, que tras procesionar solemnemente sin ellos le ser├¡an repuestos al depositar la imagen del Cristo de la Buena Muerte en la cripta del Monumento Nacional a los Ca├¡dos de la Legi├│n que se alza en los pinares de Venecia.', 1973, 1973, 1973, 'Anos 70', 'CASABLANCA', 41.62572900, -0.90612000, '0101000020E6100000740CC85EEFFEECBF53944BE317D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52796033871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52796033871.webp', 'https://www.flickr.com/photos/zaragozaantigua/52796033871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22929, 'V├¡a de la Hispanidad 1987', 'Aragonesa de Bebidas Gaseosas, Arbega, S.A., en una imagen de sus instalaciones ubicadas en la V├¡a de la Hispanidad n┬║ 31-33, frente al Seminario Metropolitano de San Valero y San Braulio. Fue constituida en 1965 al objeto de embotellar y distribuir gaseosas y bebidas refrescantes analcoh├│licas (sin alcohol), como franquicia local de una potente multinacional norteamericana del sector. Al objeto de promocionar la fidelidad de nuevas generaciones de consumidores, entre otras iniciativas la empresa practic├│ el fomento de la pol├¡tica de visitas de centros educativos a esta planta. En 1997 fue absorbida por la Compa├▒├¡a de Bebidas Gaseosas, Cobega, que reconvirti├│ las instalaciones cerr├índolas. Este suelo industrial fue recalificado como urbanizable, y vendido a una promotora que sobre buena parte del solar resultante tras el derribo promovi├│ una gran urbanizaci├│n residencial privada.', 1987, 1987, 1987, 'Anos 80', 'CASABLANCA', 41.63485200, -0.91173500, '0101000020E61000003ECBF3E0EE2CEDBF6DE690D442D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30992968871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30992968871.webp', 'https://www.flickr.com/photos/zaragozaantigua/30992968871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23011, 'Cuartel de Sanidad a├▒os 90', 'Vista de la fachada del antiguo Cuartel de Sanidad de Casablanca (V├¡a Ib├®rica 2), que albergaba las tropas de Sanidad Militar y Servicio Geogr├ífico del Ej├®rcito. Tras su derribo, la Agrupaci├│n Sanitaria se halla en la Base San Jorge de San Juan de Mozarrifar. Fuente visual: www.nrdc-sp.nato.int/inicio.html', 1990, 1990, 1999, 'Anos 90', 'CASABLANCA', 41.63159100, -0.90581600, '0101000020E6100000723106D671FCECBF56B950F9D7D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33009926772.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33009926772.webp', 'https://www.flickr.com/photos/zaragozaantigua/33009926772/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23081, 'Cuartel de Valdespartera 2003', 'Demolici├│n del antiguo cuartel de Valdespartera en 2003, como arranque de la denominada "operaci├│n Valdespartera", que preve├¡a la construcci├│n del 10.000 viviendas de precio asequible en un nuevo barrio al sur de Zaragoza, en terrenos gestionados por la sociedad Ecociudad Valdespartera. El derribo estaba presupuestado en 663.603 euros, en unas instalaciones militares que alcanzaban los 3.4 kil├│metros cuadrados. Fuente visual: Cr├│nica de Zaragoza. Ayuntamiento de Zaragoza, 2005.', 2003, 2003, 2003, 'Siglo XXI', 'CASABLANCA', 41.61966400, -0.93616300, '0101000020E61000003B35971B0CF5EDBF1841632651CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18149756583.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18149756583.webp', 'https://www.flickr.com/photos/zaragozaantigua/18149756583/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
